def compute_score() -> tuple[str, float]:
    """Score based on fraction of 'Liability' tokens replaced with 'Debt'.

    Scoring logic:
      - Count total occurrences of the exact word 'Liability' in the original presentation.
      - Count remaining occurrences of 'Liability' in the modified presentation.
      - Replaced = total - remaining; score = replaced / total (if total > 0).
      - If total == 0, return full credit (nothing to replace).
      - Provide detailed list of slides where 'Liability' still appears.
    """
    from pptx import Presentation
    import re

    pattern = re.compile(r'\bLiability\b')

    # Retrieve injected globals (runtime is expected to provide these)
    _modified_path = globals().get('modified_ppt_path')
    if not _modified_path:
        return ("modified_ppt_path not provided to scoring context.", 0.0)
    _original_path = globals().get('original_ppt_path')  # May be absent

    # Count occurrences in original (for denominator)
    if _original_path:
        try:
            orig_prs = Presentation(_original_path)
            total_original = 0
            for slide in orig_prs.slides:
                for shape in slide.shapes:
                    if hasattr(shape, 'text'):
                        total_original += len(pattern.findall(shape.text))
        except Exception:
            orig_prs = None
            total_original = None
    else:
        orig_prs = None
        total_original = None

    mod_prs = Presentation(_modified_path)
    remaining = 0
    missing_replacements = []  # Slides where Liability still present
    for i, slide in enumerate(mod_prs.slides):
        slide_num = i + 1
        for shape in slide.shapes:
            if hasattr(shape, 'text'):
                text = shape.text
                matches = pattern.findall(text)
                if matches:
                    remaining += len(matches)
                    # Capture a snippet to aid debugging (truncate long text)
                    snippet = text.strip().replace('\n', ' ')
                    if len(snippet) > 120:
                        snippet = snippet[:117] + '...'
                    missing_replacements.append(f"Slide {slide_num}: '{snippet}' ({len(matches)} instance(s))")

    if total_original is None:
        # We couldn't load the original; treat task as binary based on remaining occurrences
        if remaining == 0:
            return ("All visible 'Liability' instances replaced with 'Debt' (original unavailable for exact count).", 1.0)
        details = '\n'.join(missing_replacements)
        return (f"'Liability' still present (original unavailable for partial scoring). Remaining instances: {remaining}\n{details}", 0.0)

    # Edge case: nothing to replace originally
    if total_original == 0:
        return ("Original had no 'Liability' occurrences. Nothing to replace.", 1.0)

    replaced = total_original - remaining
    replaced = max(replaced, 0)  # Safety
    score = replaced / total_original if total_original > 0 else 1.0

    if remaining == 0:
        return (f"All {total_original} 'Liability' instance(s) replaced with 'Debt'.", 1.0)
    else:
        details = '\n'.join(missing_replacements)
        pct = f"{score*100:.1f}%"
        return (
            f"Partial replacement: {replaced}/{total_original} 'Liability' instance(s) replaced ({pct}). Remaining {remaining} instance(s) in slides below:\n{details}",
            score,
        )

