    prs_orig = Presentation(original_ppt_path)
    prs_mod = Presentation(modified_ppt_path)
    errors = []
    # Assume same number/order of slides
    for i, (s_orig, s_mod) in enumerate(zip(prs_orig.slides, prs_mod.slides)):
        slide_num = i + 1
        t_orig = []
        t_mod = []
        for sh_o in s_orig.shapes:
            if hasattr(sh_o, 'text'):
                t_orig.append(sh_o.text)
        for sh_m in s_mod.shapes:
            if hasattr(sh_m, 'text'):
                t_mod.append(sh_m.text)
        # Compare element by element (assume elements not reordered)
        for t1, t2 in zip(t_orig, t_mod):
            # If they differ, check if the difference is only 'Liability' becoming 'Debt'
            if t1 != t2:
                t1_replaced = t1.replace('Liability', 'Debt')
                if t1_replaced != t2:
                    errors.append(f"Slide {slide_num}: '{t1}' -> '{t2}'")
    if errors:
        details = '\n'.join(errors)
        return (f"Extraneous text changes found (not just 'Liability' to 'Debt'):\n{details}", 0.0)
    else:
        return ("No extraneous text changes detected.", 1.0)

